window.QUESTIONS_D4 = [
{"id":"RW-D4-01","domain":3,"cog":"AN","correct":"B","task":"Task 4.1, 4.12, 4.25","stem":"A CIO is presenting a $4M analytics platform proposal to the board. What should the presentation emphasize?","opts":[{"l":"A","c":false,"t":"Detailed database schema"},{"l":"B","c":true,"t":"Business case, strategic alignment, benefits, risks, and ROI"},{"l":"C","c":false,"t":"Screenshots of every dashboard"},{"l":"D","c":false,"t":"The vendor&#x27;s full technical manual"}],"rat":"Executive communication should connect technology investment to organizational goals and measurable value — not technical specifications."},
{"id":"RW-D4-11","domain":3,"cog":"AP","correct":"C","task":"Task 4.1","stem":"A CIO wants the IT department&#x27;s performance evaluated across four perspectives: financial returns, service quality for internal clinical customers, operational processes, and staff learning and development. This framework is:","opts":[{"l":"A","c":false,"t":"SWOT analysis"},{"l":"B","c":false,"t":"PEST analysis"},{"l":"C","c":true,"t":"Balanced Scorecard"},{"l":"D","c":false,"t":"Triple Aim"}],"rat":"The Balanced Scorecard (Kaplan &amp; Norton) measures organizational performance across Financial, Customer, Internal Process, and Learning &amp; Growth dimensions."},
{"id":"RW-D4-12","domain":3,"cog":"AN","correct":"B","task":"Task 4.2","stem":"An IT department developing a 3-year strategic plan identifies: strong clinical expertise (internal), outdated legacy infrastructure (internal), growing telehealth market demand (external), and a new federal data privacy regulation requiring costly compliance work (external). Which planning tool captures all four factors?","opts":[{"l":"A","c":false,"t":"Balanced Scorecard"},{"l":"B","c":true,"t":"SWOT analysis"},{"l":"C","c":false,"t":"Risk register"},{"l":"D","c":false,"t":"RACI matrix"}],"rat":"SWOT organizes internal Strengths and Weaknesses alongside external Opportunities and Threats into a single strategic assessment framework."},
{"id":"RW-D4-37","domain":3,"cog":"AP","correct":"B","task":"Task 4.4","stem":"A health system CIO is developing the organization&#x27;s first 3-year IT strategic plan. After conducting a SWOT analysis, what should be developed NEXT?","opts":[{"l":"A","c":false,"t":"Issue an RFP for a new EHR immediately"},{"l":"B","c":true,"t":"Develop IT goals and initiatives aligned to the organizational strategic plan, with timelines and resource requirements"},{"l":"C","c":false,"t":"Conduct staff satisfaction surveys"},{"l":"D","c":false,"t":"Publish a data dictionary"}],"rat":"An IT strategic plan translates the organizational strategy into IT initiatives, timelines, budget projections, and governance structures — not immediate procurement."},
{"id":"RW-D4-26","domain":3,"cog":"AP","correct":"B","task":"Task 4.1, 4.5","stem":"A hospital IT steering committee tracks four metrics monthly: EHR uptime percentage, average help desk ticket resolution time, end-user satisfaction score, and percentage of go-live milestones completed on time. These specific metrics were selected because they directly measure progress toward the IT department&#x27;s three-year strategic objectives. These are BEST described as:","opts":[{"l":"A","c":false,"t":"Benchmarks — external comparison standards measured against peer organizations"},{"l":"B","c":true,"t":"KPIs (Key Performance Indicators) — measurable values tied directly to strategic objectives"},{"l":"C","c":false,"t":"Balanced Scorecard financial metrics — which measure only cost and revenue outcomes"},{"l":"D","c":false,"t":"SLA commitments — contractual performance standards defined in vendor agreements"}],"rat":"KPIs are quantifiable measures selected specifically because they indicate progress toward strategic objectives. Not all metrics are KPIs — only those tied to strategic goals qualify. Benchmarks compare performance externally; SLA metrics are contractual; the Balanced Scorecard is an evaluation framework, not a metric type."},
{"id":"RW-D4-02","domain":3,"cog":"AP","correct":"B","task":"Task 4.5, 4.24","stem":"A cloud EHR vendor repeatedly misses the contract&#x27;s four-hour critical incident response time. What should the HIT leader do FIRST?","opts":[{"l":"A","c":false,"t":"Terminate the contract immediately"},{"l":"B","c":true,"t":"Formally document the SLA breach and follow the escalation/remedy process in the contract"},{"l":"C","c":false,"t":"Tell clinicians to stop submitting tickets"},{"l":"D","c":false,"t":"Pay for additional vendor services without review"}],"rat":"Vendor management starts with contract-based documentation and formal escalation before considering contract termination."},
{"id":"RW-D4-24","domain":3,"cog":"AN","correct":"B","task":"Task 4.6","stem":"Six months after deploying a new laboratory order management system, satisfaction surveys show lab technicians are dissatisfied, but results lack specificity about root causes. Before designing remediation, what should the informatics team do NEXT?","opts":[{"l":"A","c":false,"t":"Replace the system based on low satisfaction scores"},{"l":"B","c":true,"t":"Conduct focused usability observation sessions and structured interviews with laboratory staff"},{"l":"C","c":false,"t":"Increase training hours on the current system"},{"l":"D","c":false,"t":"Survey ordering physicians to cross-reference satisfaction"}],"rat":"When survey data lacks specificity, qualitative methods — observation and interviews — identify the specific usability barriers needed to guide targeted remediation."},
{"id":"RW-D4-27","domain":3,"cog":"AP","correct":"B","task":"Task 4.11","stem":"A hospital benchmarks its IT help desk performance against national peer data from the HIMSS Analytics database and finds its average ticket resolution time is 6.5 hours versus a peer median of 4.2 hours. This activity is BEST described as:","opts":[{"l":"A","c":false,"t":"Internal benchmarking"},{"l":"B","c":true,"t":"External benchmarking"},{"l":"C","c":false,"t":"Benefits realization"},{"l":"D","c":false,"t":"User satisfaction survey analysis"}],"rat":"External benchmarking compares organizational performance against industry peers or national databases. Internal benchmarking compares performance over time or across internal departments."},
{"id":"RW-D4-31","domain":3,"cog":"RE","correct":"C","task":"Task 4.6","stem":"A health system surveys patients after discharge and asks: &quot;On a scale of 0–10, how likely are you to recommend our hospital to a friend or family member?&quot; The score generated from this single question is called:","opts":[{"l":"A","c":false,"t":"KLAS rating"},{"l":"B","c":false,"t":"ALOS benchmark"},{"l":"C","c":true,"t":"Net Promoter Score (NPS)"},{"l":"D","c":false,"t":"Case Mix Index"}],"rat":"NPS (Net Promoter Score) is a simple proxy measure of customer loyalty and satisfaction based on likelihood to recommend."},
{"id":"RW-D4-05","domain":3,"cog":"AP","correct":"B","task":"Task 4.10","stem":"During contract negotiations, a vendor offers the CIO free travel to a resort &quot;innovation summit.&quot; What is the BEST response?","opts":[{"l":"A","c":false,"t":"Accept because it may improve the relationship"},{"l":"B","c":true,"t":"Decline and follow the organization&#x27;s conflict-of-interest policy"},{"l":"C","c":false,"t":"Accept only if procurement does not know"},{"l":"D","c":false,"t":"Ask the vendor to send the tickets to a colleague"}],"rat":"Gifts and complimentary travel during procurement create conflict-of-interest concerns; the ethical response is to decline and follow organizational policy."},
{"id":"RW-D4-28","domain":3,"cog":"AP","correct":"A","task":"Task 4.8","stem":"A hospital CIO wants to establish clear rules governing the use of personal smartphones for work email access. The MOST appropriate policy to create is:","opts":[{"l":"A","c":true,"t":"Acceptable Use Policy (AUP) including BYOD provisions"},{"l":"B","c":false,"t":"Data dictionary"},{"l":"C","c":false,"t":"SLA"},{"l":"D","c":false,"t":"NDA"}],"rat":"An Acceptable Use Policy defines rules for using organizational technology and systems, including BYOD (Bring Your Own Device) provisions for personal devices accessing work resources."},
{"id":"RW-D4-29","domain":3,"cog":"AN","correct":"B","task":"Task 4.9","stem":"A hospital compliance officer is establishing a new compliance program. Which of the following BEST represents the core elements of an effective healthcare compliance program per OIG guidelines?","opts":[{"l":"A","c":false,"t":"A single compliance training session per year and a helpdesk ticket system"},{"l":"B","c":true,"t":"Written policies, training and education, auditing/monitoring, open communication, enforcement/discipline, responding to detected problems, and corrective action"},{"l":"C","c":false,"t":"An SLA with each clinical department and a quarterly compliance scorecard"},{"l":"D","c":false,"t":"Annual HIPAA attestation forms signed by all employees"}],"rat":"The OIG&#x27;s seven compliance program elements are: written standards/policies, compliance officer/committee, education/training, open lines of communication, auditing/monitoring, disciplinary guidelines, and responding to detected offenses."},
{"id":"RW-D4-30","domain":3,"cog":"AN","correct":"B","task":"Task 4.10","stem":"A health system wants to use de-identified patient data to train a commercial AI diagnostic algorithm that will be sold to other health systems. What ethical concern should the HIT leader raise FIRST?","opts":[{"l":"A","c":false,"t":"Whether the algorithm vendor has signed an SLA"},{"l":"B","c":true,"t":"Whether patients were informed their data could be used for commercial AI development beyond their direct care"},{"l":"C","c":false,"t":"Whether the de-identification method uses Safe Harbor or Expert Determination"},{"l":"D","c":false,"t":"Whether the algorithm is FDA-cleared"}],"rat":"Using patient data for commercial secondary purposes raises data ethics concerns around informed consent and the scope of original data collection — separate from de-identification compliance."},
{"id":"RW-D4-39","domain":3,"cog":"AP","correct":"B","task":"Task 4.10","stem":"An IT employee discovers that the organization&#x27;s revenue cycle system contains a back-door access account created by a vendor technician, bypassing normal access controls. The employee is worried about retaliation if they report it. The organization should have which protection in place?","opts":[{"l":"A","c":false,"t":"SLA breach documentation process"},{"l":"B","c":true,"t":"Whistleblower protection policy that allows confidential reporting without fear of retaliation"},{"l":"C","c":false,"t":"A data dictionary for access log definitions"},{"l":"D","c":false,"t":"A change advisory board meeting schedule"}],"rat":"Whistleblower protections enable employees to report ethics violations, compliance issues, and security concerns without fear of retaliation — a required component of an effective compliance program."},
{"id":"RW-D4-08","domain":3,"cog":"AP","correct":"B","task":"Task 4.13","stem":"Two physician departments disagree on a standardized order set. Each argues its workflow is unique. What should the HIT leader do FIRST?","opts":[{"l":"A","c":false,"t":"Decide alone based on technical preference"},{"l":"B","c":true,"t":"Facilitate a structured consensus discussion focused on shared clinical goals and evidence"},{"l":"C","c":false,"t":"Build two unrelated order sets with no governance"},{"l":"D","c":false,"t":"Escalate directly to the board"}],"rat":"Facilitation and consensus-building are appropriate first steps before escalation; the Thomas-Kilmann collaborative approach seeks a win-win based on shared goals."},
{"id":"RW-D4-23","domain":3,"cog":"AP","correct":"B","task":"Task 4.12","stem":"An informatics manager is presenting findings on an AI diagnostic pilot to the executive committee. What presentation structure is MOST appropriate?","opts":[{"l":"A","c":false,"t":"Detailed algorithm specifications and model architecture diagrams"},{"l":"B","c":true,"t":"Clinical impact findings, cost-benefit summary, recommendation, and proposed next steps"},{"l":"C","c":false,"t":"Raw data tables and confidence intervals for all test metrics"},{"l":"D","c":false,"t":"A live vendor product demonstration"}],"rat":"Executive presentations lead with business and clinical significance, not technical detail. Format: findings → significance → recommendation → next steps."},
{"id":"RW-D4-25","domain":3,"cog":"AP","correct":"B","task":"Task 4.13","stem":"An emergency medicine department and the hospitalist group cannot agree on a common sepsis order set. Both believe their workflow is uniquely correct. Before escalating, the HIT leader should FIRST:","opts":[{"l":"A","c":false,"t":"Select the most evidence-based version and implement it without further discussion"},{"l":"B","c":true,"t":"Facilitate a structured collaborative discussion focused on shared patient safety goals and clinical evidence"},{"l":"C","c":false,"t":"Escalate immediately to the CMO for a unilateral decision"},{"l":"D","c":false,"t":"Build two separate order sets and allow each department to use their preferred version"}],"rat":"The collaborative conflict resolution approach seeks a win-win by identifying shared priorities. Escalation is appropriate only if facilitation fails; two separate order sets undermine standardization."},
{"id":"RW-D4-36","domain":3,"cog":"AP","correct":"B","task":"Task 4.15","stem":"A hospital informatics team is designing a training program for 200 nurses on a new clinical documentation system. Which adult learning principle is MOST important to incorporate?","opts":[{"l":"A","c":false,"t":"Make the content as theoretical and comprehensive as possible"},{"l":"B","c":true,"t":"Design training around realistic clinical scenarios relevant to nurses&#x27; daily work"},{"l":"C","c":false,"t":"Use only lecture-based classroom sessions for consistency"},{"l":"D","c":false,"t":"Assess learners on terminology memorization before workflow practice"}],"rat":"Adult learning (andragogy) principles prioritize self-direction, experience-based learning, relevance, and practical application — not theoretical memorization."},
{"id":"RW-D4-03","domain":3,"cog":"AN","correct":"B","task":"Task 4.2, 4.3, 4.17","stem":"The CEO wants to deploy a generative AI assistant for clinicians within 30 days. The CIO believes the use case is promising but risky. What is the BEST leadership response?","opts":[{"l":"A","c":false,"t":"Block all AI projects indefinitely"},{"l":"B","c":true,"t":"Propose governance review, risk assessment, controlled pilot, and success metrics"},{"l":"C","c":false,"t":"Deploy immediately to prove innovation"},{"l":"D","c":false,"t":"Let each department choose its own tool"}],"rat":"Leadership should balance innovation with governance, risk management, and measurable outcomes — neither blocking innovation nor deploying without controls."},
{"id":"RW-D4-04","domain":3,"cog":"AN","correct":"B","task":"Task 4.20","stem":"Nurses resist a new clinical documentation system because they believe it will slow patient care. What change management action is MOST effective?","opts":[{"l":"A","c":false,"t":"Require compliance and ignore concerns"},{"l":"B","c":true,"t":"Involve nurse champions in workflow design, testing, training, and go-live support"},{"l":"C","c":false,"t":"Replace the nursing documentation requirement"},{"l":"D","c":false,"t":"Communicate only on the day of go-live"}],"rat":"Change adoption improves when impacted users are involved early and have credible peer champions — a key principle of both Kotter and ADKAR models."},
{"id":"RW-D4-13","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"Before launching an EHR replacement project, the CIO holds town halls explaining why the current system is creating patient safety risks and limiting growth. According to Kotter&#x27;s 8-Step Change Model, this MOST directly represents:","opts":[{"l":"A","c":false,"t":"Building the guiding coalition"},{"l":"B","c":false,"t":"Sustaining acceleration"},{"l":"C","c":true,"t":"Creating a sense of urgency"},{"l":"D","c":false,"t":"Empowering broad-based action"}],"rat":"Kotter&#x27;s first step is establishing urgency by communicating why change is necessary before building a coalition or launching formal planning."},
{"id":"RW-D4-14","domain":3,"cog":"AN","correct":"D","task":"Task 4.20","stem":"Post-go-live data shows nurses scored 92% on EHR proficiency assessments but are still reverting to paper forms two months after launch. Which element of the ADKAR change model is MOST likely deficient?","opts":[{"l":"A","c":false,"t":"Knowledge"},{"l":"B","c":false,"t":"Awareness"},{"l":"C","c":false,"t":"Ability"},{"l":"D","c":true,"t":"Reinforcement"}],"rat":"High knowledge scores and demonstrated ability suggest the deficit is Reinforcement — without ongoing coaching, recognition, and accountability, learned behaviors decay back to old habits."},
{"id":"RW-D4-16","domain":3,"cog":"AP","correct":"B","task":"Task 4.17","stem":"During an EHR implementation, the project manager learns the interface vendor may have supply chain delays that could prevent the ADT interface from being ready by go-live. The MOST appropriate immediate action is to:","opts":[{"l":"A","c":false,"t":"Ignore the concern until the delay is confirmed"},{"l":"B","c":true,"t":"Log the risk in the risk register with probability, impact, mitigation strategy, and an assigned owner"},{"l":"C","c":false,"t":"Escalate directly to the board without further analysis"},{"l":"D","c":false,"t":"Move the go-live date immediately"}],"rat":"The risk register captures identified risks before they become issues, enabling proactive planning and mitigation rather than reactive crisis management."},
{"id":"RW-D4-17","domain":3,"cog":"AN","correct":"B","task":"Task 4.17","stem":"A legacy clinical application cannot be patched because the vendor has reached end-of-life, creating a known cybersecurity vulnerability. Replacement is 18 months away. The organization purchases cyber liability insurance and implements network segmentation around the application. These responses are BEST described as:","opts":[{"l":"A","c":false,"t":"Avoidance and mitigation"},{"l":"B","c":true,"t":"Transfer and mitigation"},{"l":"C","c":false,"t":"Acceptance and avoidance"},{"l":"D","c":false,"t":"Transfer and acceptance"}],"rat":"Insurance = risk transfer (shifting financial consequences); network segmentation = risk mitigation (reducing likelihood and impact). Neither avoids nor simply accepts the underlying risk."},
{"id":"RW-D4-38","domain":3,"cog":"AP","correct":"B","task":"Task 4.7, 4.18","stem":"A major EHR replacement is 6 months away. The informatics director identifies that the radiology and lab departments have not yet been included in workflow design sessions. According to stakeholder management best practices, the MOST appropriate immediate action is:","opts":[{"l":"A","c":false,"t":"Proceed without radiology and lab and address their needs post-go-live"},{"l":"B","c":true,"t":"Schedule workflow design sessions with radiology and lab representatives immediately"},{"l":"C","c":false,"t":"Send email updates to radiology and lab managers in lieu of direct engagement"},{"l":"D","c":false,"t":"Ask the vendor to manage radiology and lab communication directly"}],"rat":"Stakeholders affected by a system change must be identified and engaged early in design — late inclusion risks workflow gaps, missed requirements, and post-go-live resistance."},
{"id":"RW-D4-06","domain":3,"cog":"AP","correct":"A","task":"Task 4.23","stem":"The IT department has 18 proposed projects and funding for only 7. Which management function helps choose the best mix based on strategy, risk, value, and resources?","opts":[{"l":"A","c":true,"t":"Portfolio management"},{"l":"B","c":false,"t":"Unit testing"},{"l":"C","c":false,"t":"Release notes"},{"l":"D","c":false,"t":"Incident triage"}],"rat":"Portfolio management governs and prioritizes the entire set of projects and programs across the organization based on strategic alignment, value, risk, and resource availability."},
{"id":"RW-D4-07","domain":3,"cog":"AN","correct":"B","task":"Task 4.25","stem":"A hospital compares keeping its on-premise EHR to moving to SaaS. The SaaS subscription is lower in year one, but migration and long-term costs are uncertain. What financial analysis is MOST appropriate?","opts":[{"l":"A","c":false,"t":"Compare only the year-one subscription fee"},{"l":"B","c":true,"t":"Compare total cost of ownership over a defined time horizon"},{"l":"C","c":false,"t":"Choose the vendor with the largest customer list"},{"l":"D","c":false,"t":"Compare only hardware cost"}],"rat":"TCO captures all direct and indirect costs (hardware, software, staff, training, maintenance, migration) across the full system lifecycle for a fair comparison."},
{"id":"RW-D4-09","domain":3,"cog":"AP","correct":"B","task":"Task 4.16, 4.22","stem":"A security team lacks cloud security skills after several systems move to SaaS. What should the manager do FIRST?","opts":[{"l":"A","c":false,"t":"Wait for annual performance reviews only"},{"l":"B","c":true,"t":"Perform a competency gap assessment and create a targeted development plan"},{"l":"C","c":false,"t":"Outsource every security function permanently"},{"l":"D","c":false,"t":"Cancel all cloud projects"}],"rat":"A competency gap assessment identifies specific skill deficiencies, enabling targeted education, hiring, or sourcing decisions before the gap causes operational risk."},
{"id":"RW-D4-10","domain":3,"cog":"AN","correct":"B","task":"Task 4.19","stem":"An analytics manager presents infection-rate findings to the quality committee. The data has small sample sizes and a possible documentation change midway through the period. What should the manager include?","opts":[{"l":"A","c":false,"t":"Only the conclusion, without limitations"},{"l":"B","c":true,"t":"Findings, recommendation, data limitations, and suggested next analysis"},{"l":"C","c":false,"t":"Raw data only"},{"l":"D","c":false,"t":"A vendor sales deck"}],"rat":"Leaders must communicate recommendations clearly while disclosing data limitations that affect interpretation — avoiding overstatement of conclusions."},

{"id":"RW-D4-22","domain":3,"cog":"AN","correct":"C","task":"Task 4.22","stem":"A senior informatics director announces retirement in 18 months. The CIO begins providing two high-potential analysts with cross-functional project leadership opportunities, executive committee exposure, and mentoring. This is an example of:","opts":[{"l":"A","c":false,"t":"Competency gap assessment"},{"l":"B","c":false,"t":"360° performance feedback"},{"l":"C","c":true,"t":"Succession planning"},{"l":"D","c":false,"t":"Train-the-Trainer model"}],"rat":"Succession planning identifies and systematically develops high-potential staff to assume leadership roles before a vacancy creates organizational disruption."},
{"id":"RW-D4-15","domain":3,"cog":"AN","correct":"B","task":"Task 4.25","stem":"An IT department plans to purchase new server hardware ($800K one-time), pay annual software maintenance fees ($150K/year), and hire two system administrators ($120K/year each). How should these costs be classified?","opts":[{"l":"A","c":false,"t":"All are capital expenses"},{"l":"B","c":true,"t":"Hardware = capital; software maintenance fees and salaries = operating expenses"},{"l":"C","c":false,"t":"Hardware and software licenses = capital; salaries = operating expenses"},{"l":"D","c":false,"t":"All are operating expenses"}],"rat":"Capital budget covers one-time asset purchases (hardware); operating budget covers recurring expenses (maintenance fees, staff salaries, software subscriptions)."},
{"id":"RW-D4-18","domain":3,"cog":"AP","correct":"C","task":"Task 4.23","stem":"An IT department has 20 project proposals but budget and staffing for only 8. The CIO evaluates each against strategic goals, projected ROI, organizational risk, and resource availability to select the optimal mix. This function is called:","opts":[{"l":"A","c":false,"t":"Project management"},{"l":"B","c":false,"t":"Program management"},{"l":"C","c":true,"t":"Portfolio management"},{"l":"D","c":false,"t":"Benefits realization"}],"rat":"Portfolio management governs and optimizes the mix of projects and programs across the organization; project management manages a single initiative."},
{"id":"RW-D4-19","domain":3,"cog":"AN","correct":"B","task":"Task 4.25","stem":"A health system&#x27;s IT department wants clinical departments to see how much of the IT budget is consumed by their systems — but does not want to create interdepartmental billing friction. The MOST appropriate cost transparency model is:","opts":[{"l":"A","c":false,"t":"Chargeback"},{"l":"B","c":true,"t":"Show-back"},{"l":"C","c":false,"t":"Fixed-price contract"},{"l":"D","c":false,"t":"Time-and-materials billing"}],"rat":"Show-back reports IT costs to business units for visibility and transparency without generating an actual internal charge; chargeback directly bills departments."},
{"id":"RW-D4-20","domain":3,"cog":"AP","correct":"B","task":"Task 4.24","stem":"A clinical communications vendor has missed its contractually guaranteed 99.5% monthly uptime for three consecutive months. The FIRST formal action is:","opts":[{"l":"A","c":false,"t":"Issue an RFP for a replacement vendor"},{"l":"B","c":true,"t":"Document each SLA breach formally and initiate the escalation and remedy process defined in the contract"},{"l":"C","c":false,"t":"Terminate the contract immediately"},{"l":"D","c":false,"t":"Waive the SLA breach to preserve the relationship"}],"rat":"Formal documentation and contractual escalation are required before termination — skipping escalation may waive the organization&#x27;s contractual remedies."},
{"id":"RW-D4-35","domain":3,"cog":"RE","correct":"C","task":"Task 4.22","stem":"A manager gathers performance feedback on an IT analyst from the analyst&#x27;s direct supervisor, two peers, a direct report, and an internal customer. This 360-degree feedback approach includes all of the following EXCEPT:","opts":[{"l":"A","c":false,"t":"Supervisor feedback"},{"l":"B","c":false,"t":"Peer feedback"},{"l":"C","c":true,"t":"Self-assessment"},{"l":"D","c":false,"t":"Customer/stakeholder feedback"}],"rat":"Standard 360° feedback collects perspectives from supervisors, peers, direct reports, and stakeholders. Self-assessment is sometimes included but is not a defining element — the question tests the composition of a 360° instrument."},
{"id":"RW-D4-32","domain":3,"cog":"AP","correct":"B","task":"Task 4.23","stem":"A project manager tracks that the EHR implementation project has completed $1.2M of planned work but has spent $1.5M to do it. The Cost Performance Index (CPI) is 0.80. This means:","opts":[{"l":"A","c":false,"t":"The project is 20% ahead of schedule"},{"l":"B","c":true,"t":"The project is getting $0.80 of value for every $1.00 spent — it is over budget"},{"l":"C","c":false,"t":"The project is 20% under budget"},{"l":"D","c":false,"t":"The project has completed 80% of its scope"}],"rat":"CPI = Earned Value ÷ Actual Cost = $1.2M ÷ $1.5M = 0.80. CPI &lt; 1.0 means the project is over budget; CPI &gt; 1.0 means under budget. SPI measures schedule performance."},
{"id":"RW-D4-33","domain":3,"cog":"AN","correct":"B","task":"Task 4.24","stem":"A health system is contracting with a consulting firm for EHR implementation support. The vendor proposes a time-and-materials contract. The CIO is concerned about cost certainty. What is the PRIMARY risk of a time-and-materials contract compared to a fixed-price contract?","opts":[{"l":"A","c":false,"t":"Fixed-price contracts always include hidden fees"},{"l":"B","c":true,"t":"Time-and-materials contracts put cost risk on the buyer — total cost is unknown until work is complete"},{"l":"C","c":false,"t":"Time-and-materials contracts are illegal in healthcare settings"},{"l":"D","c":false,"t":"Fixed-price contracts do not include SOW deliverables"}],"rat":"T&amp;M contracts bill actual hours and materials — cost is open-ended and controlled by how long the work takes; fixed-price contracts transfer cost risk to the vendor."},
{"id":"RW-D4-34","domain":3,"cog":"AP","correct":"B","task":"Task 4.25","stem":"An EHR implementation project budget includes a $150K contingency reserve. A hardware delivery delay causes unexpected costs. The project manager uses $80K from the contingency reserve to cover the delay costs. What should be documented?","opts":[{"l":"A","c":false,"t":"Nothing — contingency reserves are discretionary and do not require documentation"},{"l":"B","c":true,"t":"The specific risk event, amount used, and remaining reserve balance in the project risk register and status report"},{"l":"C","c":false,"t":"A formal change control request to increase the project budget"},{"l":"D","c":false,"t":"An SLA breach notification to the hardware vendor"}],"rat":"Contingency reserves cover identified risks; each draw-down should be documented with the triggering risk event and remaining balance to maintain accurate cost reporting."},
{"id":"RW-D4-40","domain":3,"cog":"AN","correct":"B","task":"Task 4.23","stem":"A health system is simultaneously implementing a new EHR, a new revenue cycle system, and a new patient engagement platform — all sharing the same project management office, vendor partners, and executive sponsors. Managing these three initiatives together as a coordinated set to achieve the enterprise transformation goal is BEST described as:","opts":[{"l":"A","c":false,"t":"Portfolio management, because all three projects compete for the same budget"},{"l":"B","c":true,"t":"Program management, because the three projects are related and share a common organizational objective"},{"l":"C","c":false,"t":"Project management applied three times independently"},{"l":"D","c":false,"t":"Benefits realization, because outcomes are being monitored post-go-live"}],"rat":"Program management coordinates a group of related projects with a shared goal; portfolio management prioritizes across all organizational projects. These three initiatives have interdependencies and a unified transformation goal — that is a program."},
{"id":"RW-D4-41","domain":3,"cog":"AP","correct":"B","task":"Task 4.2","stem":"A health system CIO is analyzing macro-level forces that could affect the IT strategy over the next 3 years. The team examines: upcoming federal value-based care regulations, rising EHR vendor consolidation in the market, clinician burnout trends affecting technology adoption, and an influx of cloud-native health tech startups. Which environmental scanning framework organizes these factors?","opts":[{"l":"A","c":false,"t":"SWOT analysis"},{"l":"B","c":true,"t":"PEST / PESTLE analysis"},{"l":"C","c":false,"t":"Balanced Scorecard"},{"l":"D","c":false,"t":"Risk register"}],"rat":"PEST/PESTLE analyzes macro-environmental forces: Political (regulations), Economic (market consolidation), Social (burnout trends), and Technological (cloud startups) — factors outside the organization&#x27;s direct control."},
{"id":"RW-D4-42","domain":3,"cog":"AN","correct":"B","task":"Task 4.3","stem":"A health system plans to expand from 3 to 7 hospitals over 5 years. The CIO must forecast IT infrastructure needs to support this growth. Which inputs are MOST important for this forecasting exercise?","opts":[{"l":"A","c":false,"t":"Current IT staff satisfaction scores and vendor ratings"},{"l":"B","c":true,"t":"The organizational growth plan, current IT capacity data, and vendor technology roadmaps"},{"l":"C","c":false,"t":"The previous year&#x27;s capital budget only"},{"l":"D","c":false,"t":"Help desk ticket volume trends"}],"rat":"IT capacity forecasting requires the organizational growth plan (demand driver), current capacity data (baseline), and vendor roadmaps (supply constraints and opportunities) — not just historical spending."},
{"id":"RW-D4-43","domain":3,"cog":"AN","correct":"B","task":"Task 4.2, 4.20","stem":"A health system is implementing a new EHR despite a culture where physicians have historically resisted technology mandates. The CIO notes that the organization has a &quot;consensus-driven&quot; culture where decisions require broad buy-in. Which change management implication is MOST significant?","opts":[{"l":"A","c":false,"t":"The EHR implementation should be canceled to avoid conflict"},{"l":"B","c":true,"t":"Physician and clinical leader involvement in design decisions must be built into the project from the start"},{"l":"C","c":false,"t":"Culture is irrelevant if executive sponsorship is strong enough"},{"l":"D","c":false,"t":"A top-down mandate will be more efficient than consensus-building in this case"}],"rat":"Organizational culture directly shapes change management strategy. A consensus-driven culture requires co-design and early engagement — not top-down mandates that will meet resistance."},
{"id":"RW-D4-44","domain":3,"cog":"AP","correct":"B","task":"Task 4.5","stem":"An IS director needs to demonstrate EHR system availability performance to leadership each month. The MOST appropriate metric to track and report against the contracted SLA is:","opts":[{"l":"A","c":false,"t":"Number of help desk tickets submitted monthly"},{"l":"B","c":true,"t":"Monthly system uptime percentage compared to the SLA commitment"},{"l":"C","c":false,"t":"Number of active EHR users per month"},{"l":"D","c":false,"t":"Average physician documentation time per encounter"}],"rat":"System availability (uptime %) is the direct measure of SLA performance for a contracted system — it is objective, measurable, and directly tied to the vendor&#x27;s commitment."},
{"id":"RW-D4-45","domain":3,"cog":"AP","correct":"B","task":"Task 4.6, 4.11","stem":"A health system is selecting a new EHR and wants an independent assessment of vendor performance from peer healthcare organizations that have used these products. The MOST relevant data source is:","opts":[{"l":"A","c":false,"t":"The vendor&#x27;s own case studies and marketing materials"},{"l":"B","c":true,"t":"KLAS Research ratings from peer healthcare organizations"},{"l":"C","c":false,"t":"The vendor&#x27;s customer list length"},{"l":"D","c":false,"t":"The number of features in the vendor&#x27;s product brochure"}],"rat":"KLAS Research provides independent vendor performance ratings from actual healthcare customers — a standard reference for HIT vendor evaluation and comparison."},
{"id":"RW-D4-46","domain":3,"cog":"AN","correct":"C","task":"Task 4.6","stem":"A usability team wants to understand why nurses find a new medication reconciliation screen difficult to use. Rather than sending a survey, the team observes 6 nurses using the screen during actual patient care and notes specific workflow breakdowns. This approach is called:","opts":[{"l":"A","c":false,"t":"Focus group facilitation"},{"l":"B","c":false,"t":"Net Promoter Score collection"},{"l":"C","c":true,"t":"Contextual inquiry / usability observation"},{"l":"D","c":false,"t":"Benchmarking against peer organizations"}],"rat":"Contextual inquiry and usability observation reveal actual workflow breakpoints in the real work environment — more specific than surveys or focus groups for identifying specific design problems."},
{"id":"RW-D4-47","domain":3,"cog":"AP","correct":"B","task":"Task 4.7","stem":"A health system establishes a clinical informatics committee that includes the CMIO, CNIO, nursing informaticists, physician representatives, and the IT director. This committee meets monthly to prioritize EHR optimization requests, review CDS governance, and align IT projects with clinical needs. This structure represents:","opts":[{"l":"A","c":false,"t":"A departmental change advisory board"},{"l":"B","c":true,"t":"An IT governance committee that bridges clinical and IT decision-making"},{"l":"C","c":false,"t":"A vendor management steering group"},{"l":"D","c":false,"t":"A compliance audit committee"}],"rat":"Clinical informatics governance committees provide structured multi-stakeholder decision-making for EHR prioritization, CDS policy, and clinical IT alignment — a core IT governance mechanism."},
{"id":"RW-D4-48","domain":3,"cog":"AP","correct":"B","task":"Task 4.8","stem":"An IT policy review schedule stipulates that all policies are reviewed annually. However, midway through the year, a significant CMS rule change affects how patient data can be shared for quality reporting. What should the policy team do?","opts":[{"l":"A","c":false,"t":"Wait until the scheduled annual review"},{"l":"B","c":true,"t":"Trigger an off-cycle policy review immediately to address the regulatory change"},{"l":"C","c":false,"t":"Issue a verbal guidance memo and update the policy at the next annual review"},{"l":"D","c":false,"t":"Notify staff via email only and consider the policy updated"}],"rat":"IT policies should be reviewed annually OR whenever a significant regulatory, security, or organizational change requires it — waiting for the scheduled cycle creates a compliance gap."},
{"id":"RW-D4-49","domain":3,"cog":"AN","correct":"B","task":"Task 4.11","stem":"An informatics team tracks monthly EHR documentation time per nurse across three units — Unit A (12 min/patient), Unit B (18 min/patient), Unit C (8 min/patient). They compare these figures over 6 months to identify which unit optimized workflows most effectively after a documentation redesign. This activity is:","opts":[{"l":"A","c":false,"t":"External benchmarking"},{"l":"B","c":true,"t":"Internal benchmarking"},{"l":"C","c":false,"t":"Benefits realization"},{"l":"D","c":false,"t":"Satisfaction survey analysis"}],"rat":"Internal benchmarking compares performance across internal departments or over time within the same organization — here comparing three units against each other over 6 months."},
{"id":"RW-D4-50","domain":3,"cog":"AP","correct":"B","task":"Task 4.12","stem":"A project manager needs to communicate EHR implementation progress to the executive steering committee. What is the MOST appropriate format?","opts":[{"l":"A","c":false,"t":"A detailed technical change log from the past sprint"},{"l":"B","c":true,"t":"A concise project status report showing schedule, budget, scope, risk status, and key decisions needed"},{"l":"C","c":false,"t":"A full copy of the project plan with all task-level details"},{"l":"D","c":false,"t":"A vendor invoice summary"}],"rat":"Executive steering committees need executive-level project status: RAG (red/amber/green) status on scope/schedule/budget, key risks, and decisions requiring executive action — not operational details."},
{"id":"RW-D4-51","domain":3,"cog":"AN","correct":"B","task":"Task 4.13","stem":"During a governance meeting, two department heads are in prolonged conflict over IT resource allocation. One party refuses to compromise and insists on getting everything requested. The HIT leader has already attempted collaboration twice without resolution. The MOST appropriate next step is:","opts":[{"l":"A","c":false,"t":"Let the conflict continue until one party gives up"},{"l":"B","c":true,"t":"Apply the competing conflict style — make a decision and impose it to break the deadlock"},{"l":"C","c":false,"t":"Avoid the conflict by deferring all resource allocation decisions"},{"l":"D","c":false,"t":"Accommodate one party&#x27;s full request to resolve the conflict quickly"}],"rat":"After collaboration fails, the Thomas-Kilmann competing style (using authority to make a decision) is appropriate to break a deadlock — it should be used after collaborative approaches are exhausted."},
{"id":"RW-D4-52","domain":3,"cog":"AP","correct":"B","task":"Task 4.14","stem":"A clinical department director asks the IT informatics team: &quot;We want to reduce patient no-show rates. What technology could help?&quot; The informaticist evaluates the problem, analyzes patient data, and recommends an automated reminder system integrated with the scheduling platform. This role is BEST described as:","opts":[{"l":"A","c":false,"t":"Help desk support"},{"l":"B","c":true,"t":"HIT leader acting as a consultative technology advisor"},{"l":"C","c":false,"t":"Vendor sales representative"},{"l":"D","c":false,"t":"Data warehouse administrator"}],"rat":"Providing consultative technology services means translating a business or clinical problem into a technology recommendation — a core HIT leadership competency."},
{"id":"RW-D4-53","domain":3,"cog":"AP","correct":"C","task":"Task 4.15","stem":"An informatics team needs to train 300 providers on new CDS tools. Some providers are in remote rural clinics; others are in urban hospitals with varying schedules. The training director proposes combining asynchronous online modules for concept learning with short in-person sessions for hands-on workflow practice. This is called:","opts":[{"l":"A","c":false,"t":"Train-the-Trainer"},{"l":"B","c":false,"t":"Computer-based learning only"},{"l":"C","c":true,"t":"Blended learning"},{"l":"D","c":false,"t":"At-the-Elbow support"}],"rat":"Blended learning combines multiple modalities (CBL/eLearning for self-paced concept learning + classroom/simulation for hands-on practice) to reach diverse learner needs efficiently."},
{"id":"RW-D4-54","domain":3,"cog":"AP","correct":"B","task":"Task 4.16","stem":"An IS director wants to stay current on emerging health IT standards, develop peer networks, and earn continuing education credits toward CPHIMS renewal. Which activity is MOST aligned with all three goals?","opts":[{"l":"A","c":false,"t":"Attending a vendor product demonstration"},{"l":"B","c":true,"t":"Participating in HIMSS annual conference and regional chapter events"},{"l":"C","c":false,"t":"Reading internal organizational reports"},{"l":"D","c":false,"t":"Completing mandatory compliance training modules"}],"rat":"Professional organizations like HIMSS offer conferences, peer networking, and continuing education — the primary venues for HIT professionals to maintain and expand competencies."},
{"id":"RW-D4-55","domain":3,"cog":"AN","correct":"B","task":"Task 4.17","stem":"A health system&#x27;s board of directors has a stated policy that IT projects may not expose the organization to more than a 15% probability of a major clinical disruption without executive sign-off. This policy statement defines the organization&#x27;s:","opts":[{"l":"A","c":false,"t":"Risk register threshold"},{"l":"B","c":true,"t":"Risk appetite"},{"l":"C","c":false,"t":"Contingency reserve limit"},{"l":"D","c":false,"t":"SLA penalty clause"}],"rat":"Risk appetite is the level of risk an organization is willing to accept in pursuit of its objectives. It guides risk response decisions throughout the organization."},
{"id":"RW-D4-56","domain":3,"cog":"AP","correct":"B","task":"Task 4.17","stem":"A project team identifies a risk that the primary EHR integration vendor may be acquired, potentially disrupting the implementation timeline. The team assigns this risk a likelihood of 3/5 and an impact of 5/5, yielding a risk score of 15. This is an example of:","opts":[{"l":"A","c":false,"t":"Quantitative risk analysis using financial models"},{"l":"B","c":true,"t":"Qualitative risk analysis using probability and impact scoring"},{"l":"C","c":false,"t":"Benefits realization assessment"},{"l":"D","c":false,"t":"Earned value management"}],"rat":"Qualitative risk analysis uses probability × impact scales to prioritize risks without requiring financial quantification — a practical first step in risk assessment for most IT projects."},
{"id":"RW-D4-57","domain":3,"cog":"AN","correct":"B","task":"Task 4.17, 4.24","stem":"A health system&#x27;s EHR, revenue cycle system, and clinical analytics platform are all provided by the same single vendor. The CIO is reviewing vendor risk. What is the PRIMARY concern with this arrangement?","opts":[{"l":"A","c":false,"t":"The vendor is likely to offer volume discounts"},{"l":"B","c":true,"t":"Vendor concentration risk — a single vendor failure or acquisition could disrupt all three critical systems"},{"l":"C","c":false,"t":"The organization will have too many integration interfaces to manage"},{"l":"D","c":false,"t":"The vendor will charge more for bundled services"}],"rat":"Vendor concentration risk (also called single-source dependency) means that a vendor&#x27;s financial instability, acquisition, or service failure could simultaneously impact all dependent systems — a key risk management consideration."},
{"id":"RW-D4-58","domain":3,"cog":"AP","correct":"B","task":"Task 4.20","stem":"After creating urgency for an EHR replacement, the CIO forms a team of influential physician leaders, nurse managers, IT directors, and the CFO to guide the project and remove organizational barriers. According to Kotter&#x27;s 8-Step Model, this is:","opts":[{"l":"A","c":false,"t":"Step 1: Create urgency"},{"l":"B","c":true,"t":"Step 2: Build the guiding coalition"},{"l":"C","c":false,"t":"Step 5: Empower broad-based action"},{"l":"D","c":false,"t":"Step 7: Sustain acceleration"}],"rat":"Kotter&#x27;s Step 2 is building a guiding coalition — a group with enough credibility, authority, and diversity to lead the change and overcome resistance across the organization."},
{"id":"RW-D4-59","domain":3,"cog":"AN","correct":"C","task":"Task 4.20","stem":"An EHR implementation team achieves several early workflow improvements — physicians report faster order entry and nurses complete morning assessments 20% faster in the first month. The CIO publicizes these wins widely. According to Kotter&#x27;s 8-Step Model, this strategy represents:","opts":[{"l":"A","c":false,"t":"Step 3: Develop a vision"},{"l":"B","c":false,"t":"Step 4: Communicate the vision"},{"l":"C","c":true,"t":"Step 6: Generate short-term wins"},{"l":"D","c":false,"t":"Step 8: Anchor change in the culture"}],"rat":"Kotter&#x27;s Step 6 (Generate Short-Term Wins) involves creating and publicizing visible improvements early in the change process to build momentum and credibility."},
{"id":"RW-D4-60","domain":3,"cog":"AN","correct":"C","task":"Task 4.20","stem":"An informatics team assesses ADKAR status for a new clinical decision support rollout. Surveys show 95% of physicians are Aware of the change and 88% have Knowledge of how to use the new alerts. However, only 42% report wanting to use the new alerts in their workflow. Which ADKAR element is MOST deficient?","opts":[{"l":"A","c":false,"t":"Awareness"},{"l":"B","c":false,"t":"Knowledge"},{"l":"C","c":true,"t":"Desire"},{"l":"D","c":false,"t":"Ability"}],"rat":"Desire is the willingness to participate in and support the change. High Awareness and Knowledge but low intent to use indicates the Desire element needs focused attention — through clinical engagement, champion support, and demonstrating personal relevance."},
{"id":"RW-D4-61","domain":3,"cog":"AP","correct":"B","task":"Task 4.21","stem":"An IT director is creating a job description for a new clinical informatics analyst role. Which components are MOST critical to include?","opts":[{"l":"A","c":false,"t":"The employee&#x27;s preferred work schedule and vacation policy"},{"l":"B","c":true,"t":"Role title, reporting structure, key responsibilities, required competencies, and minimum qualifications"},{"l":"C","c":false,"t":"The department&#x27;s annual budget and headcount"},{"l":"D","c":false,"t":"A list of all projects the employee will work on in year one"}],"rat":"A job description defines the role clearly for recruiting and performance management: title, reporting relationship, responsibilities, required competencies (skills/certifications), and qualifications."},
{"id":"RW-D4-62","domain":3,"cog":"AP","correct":"B","task":"Task 4.23","stem":"An EHR project&#x27;s Schedule Performance Index (SPI) is 0.85. What does this indicate?","opts":[{"l":"A","c":false,"t":"The project is 15% under budget"},{"l":"B","c":true,"t":"The project is behind schedule — only 85% of planned work has been completed per dollar spent"},{"l":"C","c":false,"t":"The project is 15% ahead of schedule"},{"l":"D","c":false,"t":"The project has completed 85% of its total scope"}],"rat":"SPI = Earned Value ÷ Planned Value. SPI &lt; 1.0 means behind schedule (less work completed than planned); SPI &gt; 1.0 means ahead of schedule. CPI measures cost performance."},
{"id":"RW-D4-63","domain":3,"cog":"AP","correct":"B","task":"Task 4.23","stem":"A health system establishes a centralized department that provides standardized project management methodology, templates, training, and oversight for all IT projects across the organization. This function is called:","opts":[{"l":"A","c":false,"t":"Change Advisory Board"},{"l":"B","c":true,"t":"Project Management Office (PMO)"},{"l":"C","c":false,"t":"Data governance council"},{"l":"D","c":false,"t":"Clinical informatics committee"}],"rat":"A PMO centralizes project management standards, tools, oversight, and support — ensuring consistency across the organization&#x27;s project portfolio."},
{"id":"RW-D4-64","domain":3,"cog":"AN","correct":"B","task":"Task 4.24, 4.17","stem":"A health system relies on a single specialty EHR vendor for its oncology, cardiology, and ophthalmology departments. The vendor announces it is being acquired by a large EHR competitor and may discontinue the specialty modules within 18 months. What is the PRIMARY risk management concern?","opts":[{"l":"A","c":false,"t":"The new vendor will require renegotiating SLA response times"},{"l":"B","c":true,"t":"Vendor concentration risk — simultaneous disruption of three specialty departments with no backup alternatives"},{"l":"C","c":false,"t":"The acquisition will improve the product roadmap and is therefore beneficial"},{"l":"D","c":false,"t":"Help desk ticket volume will temporarily increase"}],"rat":"Single-vendor dependency across multiple critical systems amplifies the impact of vendor instability. Organizations should maintain vendor diversification and contract protections (source code escrow, transition assistance clauses) to mitigate this risk."},
{"id":"RW-D4-65","domain":3,"cog":"AN","correct":"B","task":"Task 4.25","stem":"A hospital is deciding between two EHR upgrade paths. Option A costs $500K upfront with $50K annual maintenance. Option B costs $150K upfront with $120K annual maintenance. The organization&#x27;s planning horizon is 5 years. Which financial analysis BEST determines which option is more cost-effective over the full period?","opts":[{"l":"A","c":false,"t":"Compare only the year-one costs"},{"l":"B","c":true,"t":"Calculate the Net Present Value (NPV) or Total Cost of Ownership (TCO) over 5 years for each option"},{"l":"C","c":false,"t":"Choose the option with the lower upfront cost"},{"l":"D","c":false,"t":"Select the option preferred by the EHR vendor"}],"rat":"Option A 5-year TCO = $500K + (5 × $50K) = $750K. Option B 5-year TCO = $150K + (5 × $120K) = $750K. They are equal at 5 years — NPV/TCO analysis reveals this; year-one comparison alone ($500K vs $150K) would incorrectly favor Option B."},
{"id":"RW-D4-66","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"A hospital is launching a new telehealth platform that will replace the current video visit tool in 90 days. A pre-launch survey shows 60% of nursing staff are unaware the change is happening. Which ADKAR element must be addressed FIRST?","opts":[{"l":"A","c":false,"t":"Ability — nurses need hands-on training before go-live"},{"l":"B","c":false,"t":"Desire — nurses must want to switch platforms"},{"l":"C","c":true,"t":"Awareness — nurses must understand that the change is happening and why it matters"},{"l":"D","c":false,"t":"Reinforcement — nurses need post-go-live coaching"}],"rat":"ADKAR is sequential: Awareness → Desire → Knowledge → Ability → Reinforcement. Without Awareness that a change is coming and why, no subsequent element can be built. Sixty percent unaware is a critical Awareness gap."},
{"id":"RW-D4-67","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"After successfully building awareness and desire for a new EHR documentation system among nurses, the informatics team begins formal training sessions on how to use the new workflows, complete required fields, and navigate the new screen layouts. Which ADKAR element is being addressed?","opts":[{"l":"A","c":false,"t":"Awareness"},{"l":"B","c":false,"t":"Desire"},{"l":"C","c":true,"t":"Knowledge"},{"l":"D","c":false,"t":"Reinforcement"}],"rat":"Knowledge in ADKAR means having the information and training needed to know how to change — including skills, workflows, and understanding of the new system. It follows Awareness (knowing a change is happening) and Desire (wanting to change)."},
{"id":"RW-D4-68","domain":3,"cog":"AN","correct":"D","task":"Task 4.20","stem":"A hospital provides comprehensive EHR training (100% completion rate) and staff express genuine desire to adopt the new system. However, on go-live day, nurses take 3× longer than expected to complete documentation tasks and frequently need help. Which ADKAR element is deficient?","opts":[{"l":"A","c":false,"t":"Awareness — nurses don&#x27;t know the system has launched"},{"l":"B","c":false,"t":"Knowledge — nurses were not adequately trained"},{"l":"C","c":false,"t":"Desire — nurses lack motivation to use the new system"},{"l":"D","c":true,"t":"Ability — nurses have knowledge but lack the practiced skill to perform tasks efficiently"}],"rat":"Ability is demonstrated proficiency — the capacity to perform new tasks efficiently in the real work environment. Knowledge (knowing how in theory) does not guarantee Ability (doing it efficiently in practice). Ability develops through hands-on practice and at-the-elbow coaching, not just classroom training."},
{"id":"RW-D4-69","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"After creating urgency and assembling a guiding coalition for an EHR replacement, the CIO works with clinical and operational leaders to articulate a compelling picture of where the organization will be in 3 years — including specific improvements in patient safety, workflow efficiency, and care coordination. According to Kotter&#x27;s model, this is:","opts":[{"l":"A","c":false,"t":"Step 1: Create a sense of urgency"},{"l":"B","c":false,"t":"Step 2: Build the guiding coalition"},{"l":"C","c":true,"t":"Step 3: Form a strategic vision and initiatives"},{"l":"D","c":false,"t":"Step 4: Communicate the change vision broadly"}],"rat":"Kotter Step 3 involves developing a clear, compelling, and specific vision of the desired future state — something specific enough to guide decisions and inspiring enough for stakeholders to rally around. It is distinct from urgency (why change) and communication (spreading the vision)."},
{"id":"RW-D4-70","domain":3,"cog":"AP","correct":"D","task":"Task 4.20","stem":"The CIO presents the EHR replacement vision at all-hands meetings, includes it in weekly department newsletters, asks physician champions to discuss it at medical staff meetings, and references it at every leadership update for 6 months. According to Kotter&#x27;s model, this intensive activity represents:","opts":[{"l":"A","c":false,"t":"Create urgency — explaining why change is necessary"},{"l":"B","c":false,"t":"Build the guiding coalition — expanding leadership support"},{"l":"C","c":false,"t":"Form the vision — developing what the future will look like"},{"l":"D","c":true,"t":"Communicate the change vision broadly and repeatedly"}],"rat":"Kotter Step 4 is communicating the vision through every available channel, repeatedly and consistently — using the guiding coalition as amplifiers. Change communication must reach all organizational levels through multiple media."},
{"id":"RW-D4-71","domain":3,"cog":"AN","correct":"B","task":"Task 4.20","stem":"Six months into an EHR implementation, a physician champion reports that she wants to adopt the new workflows but her department&#x27;s scheduling system is not yet integrated — forcing her to use two systems for every patient. According to Kotter, the change management team&#x27;s BEST response is:","opts":[{"l":"A","c":false,"t":"Ask the physician to be patient until the integration is complete next year"},{"l":"B","c":true,"t":"Identify this as a structural barrier and prioritize the scheduling integration to remove the obstacle"},{"l":"C","c":false,"t":"Replace the physician champion with someone who experiences fewer barriers"},{"l":"D","c":false,"t":"Add the issue to the risk register without an action plan"}],"rat":"Kotter Step 5 (Empower Broad-Based Action) involves identifying and removing structural, technical, and organizational barriers that prevent people from acting on the change vision. Unresolved barriers signal that the organization does not truly support the change it claims to champion."},
{"id":"RW-D4-72","domain":3,"cog":"AN","correct":"C","task":"Task 4.20","stem":"A health system celebrates its 6-month EHR go-live milestone with an organization-wide celebration, and the CIO declares &quot;the digital transformation is complete.&quot; Three months later, staff begin reverting to paper workarounds and optimization momentum stalls. According to Kotter, what change management mistake was made?","opts":[{"l":"A","c":false,"t":"The guiding coalition was too small to sustain momentum"},{"l":"B","c":false,"t":"The change vision was not compelling enough"},{"l":"C","c":true,"t":"Victory was declared too soon — Kotter&#x27;s Step 7 specifically warns against premature victory declarations"},{"l":"D","c":false,"t":"The urgency created in Step 1 was insufficient"}],"rat":"Kotter Step 7 (Sustain Acceleration) warns explicitly against declaring victory prematurely. Celebrating milestones is appropriate and necessary; declaring the transformation complete before behaviors are embedded allows complacency and regression to old habits."},
{"id":"RW-D4-73","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"Two years after an EHR go-live, the health system updates new employee orientation to include EHR proficiency as a standard onboarding requirement and begins recognizing physicians who use analytics data in clinical decision-making in performance reviews. According to Kotter, this represents:","opts":[{"l":"A","c":false,"t":"Step 6: Generate short-term wins"},{"l":"B","c":false,"t":"Step 7: Sustain acceleration"},{"l":"C","c":true,"t":"Step 8: Anchor change in the organizational culture"},{"l":"D","c":false,"t":"Step 2: Build the guiding coalition"}],"rat":"Kotter Step 8 (Anchor Change in Culture) embeds new behaviors in organizational systems — hiring criteria, onboarding programs, recognition, and performance management — so the change becomes &quot;how we do things here&quot; rather than a temporary initiative."},
{"id":"RW-D4-74","domain":3,"cog":"AN","correct":"B","task":"Task 4.20","stem":"During an EHR go-live, a group of experienced emergency physicians refuses to use the new documentation templates, arguing they are &quot;too slow&quot; and &quot;designed by people who don&#x27;t understand emergency medicine.&quot; The BEST initial change management response is to:","opts":[{"l":"A","c":false,"t":"Mandate compliance immediately and issue sanctions for continued non-use"},{"l":"B","c":true,"t":"Investigate whether the workflow concerns are valid, involve the physicians in rapid optimization, and address legitimate usability issues"},{"l":"C","c":false,"t":"Replace resistant physicians with locum physicians who will use the system"},{"l":"D","c":false,"t":"Create separate unconstrained documentation templates without governance review"}],"rat":"Resistance rooted in legitimate usability concerns requires investigation and co-design — not mandate. Addressing root causes (valid workflow problems) builds credibility and accelerates adoption. Mandates without resolution breed deeper resistance and workarounds."},
{"id":"RW-D4-75","domain":3,"cog":"AP","correct":"B","task":"Task 4.20","stem":"A major EHR implementation has a COO who authorizes the project, removes organizational barriers, and provides visible leadership support. Separately, a network of physician and nurse &quot;super-users&quot; are trained on the system and serve as peer coaches during go-live. Which statement BEST describes their distinct change management roles?","opts":[{"l":"A","c":false,"t":"The sponsor and champions perform identical functions at different organizational levels"},{"l":"B","c":true,"t":"The sponsor provides executive authority, resources, and accountability; champions provide peer credibility, hands-on coaching, and ground-level adoption influence"},{"l":"C","c":false,"t":"Champions have more organizational authority than executive sponsors"},{"l":"D","c":false,"t":"Sponsors manage go-live logistics; champions manage executive communication"}],"rat":"Executive sponsors provide organizational legitimacy, resource allocation, and barrier removal at leadership level. Change champions provide peer influence, hands-on coaching, and credibility among frontline staff — two distinct and complementary roles in any successful change management program."},
{"id":"RW-D4-76","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"Before launching a major clinical documentation redesign, the informatics director surveys 200 clinicians on their awareness of the change, perceived need for it, and confidence in their ability to adapt. Results will shape the change management intervention plan. This pre-change activity is called:","opts":[{"l":"A","c":false,"t":"Benefits realization assessment"},{"l":"B","c":false,"t":"Gap analysis"},{"l":"C","c":true,"t":"Change readiness assessment"},{"l":"D","c":false,"t":"SWOT analysis"}],"rat":"A change readiness assessment evaluates how prepared an organization is for a specific change — measuring awareness, desire, perceived capacity, and concerns before the change management plan is finalized. Results guide resource allocation for communication, training, and coaching."},
{"id":"RW-D4-77","domain":3,"cog":"AN","correct":"B","task":"Task 4.20","stem":"A health system launches a new clinical analytics platform and notifies all staff via a single email sent two days before go-live. Adoption after launch is extremely low. The MOST likely change management root cause is:","opts":[{"l":"A","c":false,"t":"The system was not properly tested before go-live"},{"l":"B","c":true,"t":"A single last-minute announcement is insufficient — effective change communication requires early, repeated, multichannel messaging to build awareness, desire, and readiness"},{"l":"C","c":false,"t":"The system lacked features requested by clinical staff"},{"l":"D","c":false,"t":"The project budget was inadequate for the scope"}],"rat":"Effective change communication requires multiple touchpoints across multiple channels (email, town halls, unit huddles, leadership messages, screensavers), beginning weeks to months before go-live. A single announcement two days before cannot build the ADKAR progression needed for adoption."},
{"id":"RW-D4-78","domain":3,"cog":"AP","correct":"C","task":"Task 4.20, 4.7","stem":"Before deploying a new revenue cycle system, the change management team maps which groups — billing staff, coders, patient access representatives, finance analysts — will experience the most significant workflow changes, and rates each group&#x27;s capacity to absorb the change. This planning activity is called:","opts":[{"l":"A","c":false,"t":"RACI matrix development"},{"l":"B","c":false,"t":"Risk register creation"},{"l":"C","c":true,"t":"Stakeholder impact analysis for change management"},{"l":"D","c":false,"t":"Competency gap assessment"}],"rat":"Stakeholder impact analysis identifies who is affected by a change, how significantly their workflows will change, and how ready they are to adapt — enabling the change management team to prioritize training, communication, and support resources for highest-impact groups."},
{"id":"RW-D4-79","domain":3,"cog":"AN","correct":"C","task":"Task 4.20, 4.15","stem":"A health system schedules all EHR training 8–10 weeks before go-live. By go-live day, many nurses report they have forgotten most of the content. The ADKAR element most directly affected by poor training timing is:","opts":[{"l":"A","c":false,"t":"Awareness — nurses don&#x27;t know the system is launching"},{"l":"B","c":false,"t":"Desire — nurses are no longer motivated to use the system"},{"l":"C","c":true,"t":"Knowledge — training provided too far from go-live results in significant skill decay before first use"},{"l":"D","c":false,"t":"Reinforcement — no post-go-live support was planned"}],"rat":"Training provided too far from go-live causes knowledge decay — people forget skills they cannot immediately apply. Best practice is &quot;just-in-time&quot; training 2–4 weeks before go-live, supplemented with job aids available at the point of care on day one."},
{"id":"RW-D4-80","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"An IS director planning a new medication ordering workflow redesign lists factors supporting adoption (improved safety alerts, faster order entry, physician champion support) alongside factors resisting adoption (habit, fear of slowdown, past negative EHR experience). This analysis technique is called:","opts":[{"l":"A","c":false,"t":"SWOT analysis"},{"l":"B","c":false,"t":"RACI matrix"},{"l":"C","c":true,"t":"Force field analysis"},{"l":"D","c":false,"t":"PEST analysis"}],"rat":"Force field analysis (Lewin) maps driving forces (supporting the change) against restraining forces (opposing the change) — helping change managers strategically strengthen drivers and reduce resistors to tip the organizational balance toward adoption."},
{"id":"RW-D4-81","domain":3,"cog":"AN","correct":"C","task":"Task 4.20","stem":"An informatics team assesses ADKAR for a new clinical decision support rollout. Surveys show 95% of physicians are Aware of the change and 88% have Knowledge of how to use the new alerts. However, only 42% report wanting to use the alerts in their workflow. Which ADKAR element needs focused intervention?","opts":[{"l":"A","c":false,"t":"Awareness — only 95% is not sufficient"},{"l":"B","c":false,"t":"Knowledge — 88% is below acceptable threshold"},{"l":"C","c":true,"t":"Desire — physicians have awareness and knowledge but insufficient motivation to change their behavior"},{"l":"D","c":false,"t":"Ability — physicians cannot use the alerts efficiently"}],"rat":"High Awareness and Knowledge but low intent to use indicates Desire is the missing element. Desire interventions include involving physicians in alert design, sharing outcome data, addressing WIIFMs (What&#x27;s In It For Me), and peer influence from physician champions."},
{"id":"RW-D4-82","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"A project manager notices that an EHR go-live achieved a major workflow milestone — physicians&#x27; average order entry time dropped by 40% in the first month. The CIO shares this win publicly with all staff to maintain momentum and demonstrate progress. According to Kotter, this strategy aligns with:","opts":[{"l":"A","c":false,"t":"Step 3: Form the change vision"},{"l":"B","c":false,"t":"Step 5: Remove barriers to action"},{"l":"C","c":true,"t":"Step 6: Generate and celebrate short-term wins"},{"l":"D","c":false,"t":"Step 8: Anchor change in culture"}],"rat":"Kotter Step 6 (Generate Short-Term Wins) involves creating visible, measurable improvements early in the transformation and communicating them broadly to build credibility, reward change champions, and maintain momentum against resistance."},
{"id":"RW-D4-83","domain":3,"cog":"AN","correct":"B","task":"Task 4.20","stem":"After 18 months of EHR adoption, a health system surveys clinicians and finds that most high-risk workarounds have been eliminated, but documentation quality is still inconsistent in two surgical departments. The change management team argues the EHR transformation is &quot;mostly complete.&quot; According to change management best practices, what is the MOST appropriate response?","opts":[{"l":"A","c":false,"t":"Declare success and close the change management program"},{"l":"B","c":true,"t":"Continue structured change management interventions in the two lagging departments until outcomes meet targets"},{"l":"C","c":false,"t":"Issue disciplinary notices to the two surgical departments"},{"l":"D","c":false,"t":"Replace the surgical department superusers with corporate informatics staff"}],"rat":"Change management is not complete until desired behaviors are consistently embedded across all target groups. Declaring success while two departments still show inconsistent adoption risks regression and signals that incomplete adoption is acceptable."},
{"id":"RW-D4-84","domain":3,"cog":"AP","correct":"B","task":"Task 4.20","stem":"A hospital&#x27;s change management team is planning for a significant EHR upgrade. They want to identify the specific individuals who are most influential among frontline nursing staff — those whose endorsement would most persuade their peers to adopt new workflows. Which change management activity are they conducting?","opts":[{"l":"A","c":false,"t":"Stakeholder impact analysis — rating groups by degree of change exposure"},{"l":"B","c":true,"t":"Identification of informal change champions / opinion leaders"},{"l":"C","c":false,"t":"Force field analysis — mapping driving and restraining forces"},{"l":"D","c":false,"t":"ADKAR assessment — measuring individual change readiness"}],"rat":"Identifying informal opinion leaders (influential frontline peers whose colleagues trust and follow) is a targeted change management strategy. These individuals, when engaged as champions, have more peer-level credibility than formal leadership — accelerating grassroots adoption."},
{"id":"RW-D4-85","domain":3,"cog":"AN","correct":"B","task":"Task 4.20","stem":"A large health system is implementing a new patient safety reporting system. The change management assessment reveals: (1) most staff understand why the change is needed (high Awareness), (2) staff express concern that reporting errors will lead to punishment (low Desire), (3) training has not yet occurred (Knowledge gap), and (4) go-live is in 6 weeks. Which intervention should the change management team prioritize FIRST?","opts":[{"l":"A","c":false,"t":"Accelerate training delivery immediately to address the Knowledge gap before go-live"},{"l":"B","c":true,"t":"Address the Desire gap first — clarify the non-punitive reporting culture and leadership commitment to psychological safety"},{"l":"C","c":false,"t":"Launch go-live as planned without addressing the Desire concern"},{"l":"D","c":false,"t":"Delay go-live until all ADKAR elements reach 90%+ on the survey"}],"rat":"ADKAR is sequential. Staff will not engage in training (Knowledge) or practice new skills (Ability) until they want to (Desire). Addressing the punitive culture concern — the root of low Desire — must precede training. Training delivered to unwilling learners produces minimal Knowledge retention."},
{"id":"RW-D4-86","domain":3,"cog":"AN","correct":"B","task":"Task 4.20","stem":"A CIO consistently connects the EHR optimization initiative to the organization&#x27;s patient safety mission. She holds individual sessions with frontline staff explaining how their documentation improvements directly prevent specific medication errors. Staff report feeling deeply committed to the work far beyond their contractual obligations and describe the CIO&#x27;s leadership as inspiring. This leadership approach is BEST described as:","opts":[{"l":"A","c":false,"t":"Transactional leadership — motivating through performance incentives tied to project milestones"},{"l":"B","c":true,"t":"Transformational leadership — inspiring followers through vision, meaning, and intrinsic motivation"},{"l":"C","c":false,"t":"Servant leadership — focusing on removing barriers that prevent the team from completing their work"},{"l":"D","c":false,"t":"Situational leadership — adapting style to individual team member development levels"}],"rat":"Transformational leadership inspires followers by connecting work to a higher purpose and vision, generating intrinsic commitment beyond extrinsic rewards. It contrasts with transactional (reward/punishment for performance), servant (removing obstacles for the team), and situational (adapting style to follower maturity level)."},
{"id":"RW-D4-87","domain":3,"cog":"AP","correct":"C","task":"Task 4.20","stem":"An IT director learns her implementation team is blocked because they need approvals from clinical department heads who are not responding to meeting requests. Rather than instructing the team on how to work around it, she personally contacts each department head, clears scheduling conflicts, and eliminates three bureaucratic approval hurdles the team had identified. This leadership behavior BEST reflects:","opts":[{"l":"A","c":false,"t":"Transformational leadership — inspiring the team through an organizational vision"},{"l":"B","c":false,"t":"Transactional leadership — offering team members a reward in exchange for cooperation"},{"l":"C","c":true,"t":"Servant leadership — placing the team&#x27;s needs first and removing obstacles to enable their success"},{"l":"D","c":false,"t":"Competing conflict style — asserting authority to break an organizational deadlock"}],"rat":"Servant leadership is defined by the leader prioritizing the needs of the team and focusing on enabling others&#x27; success — removing obstacles, reducing friction, and supporting rather than directing. The leader serves the team, not the other way around."},
{"id":"RW-D4-88","domain":3,"cog":"AN","correct":"A","task":"Task 4.21","stem":"A new clinical informatics analyst joins the team directly from a nursing role. She has no prior EHR configuration or informatics systems experience but is highly enthusiastic and eager to learn. Using the Hersey-Blanchard Situational Leadership model, which leadership style should her manager apply?","opts":[{"l":"A","c":true,"t":"Directing (S1) — high task, low relationship: tell her specifically what to do, how, and when"},{"l":"B","c":false,"t":"Coaching (S2) — high task and high relationship: explain both the how and the why with strong personal support"},{"l":"C","c":false,"t":"Supporting (S3) — low task, high relationship: listen to her ideas and encourage her to make decisions"},{"l":"D","c":false,"t":"Delegating (S4) — low task, low relationship: hand off assignments and trust her to work independently"}],"rat":"A D1 follower (Enthusiastic Beginner) has low task competence but high commitment. The matching style is S1 Directing — provide specific, structured task guidance (what, how, when) because the follower lacks the skills to make sound independent decisions. Delegating would be dangerous at this stage regardless of her enthusiasm."},
{"id":"RW-D4-89","domain":3,"cog":"AN","correct":"B","task":"Task 4.21","stem":"An EHR go-live project involves many parties: the project manager coordinates logistics, the CMIO provides clinical readiness input, the CNO reviews nursing workflow validation, and the vendor supplies interface test results. The CIO makes the final call on whether to proceed or delay go-live. In the RACI matrix for the go/no-go decision, which role does the CIO hold?","opts":[{"l":"A","c":false,"t":"Responsible — the CIO performs the most evaluation work"},{"l":"B","c":true,"t":"Accountable — the CIO is the single owner answerable for the outcome of the decision"},{"l":"C","c":false,"t":"Consulted — the CIO provides input but does not hold final authority"},{"l":"D","c":false,"t":"Informed — the CIO is notified after the project team makes the decision"}],"rat":"Accountable (A) in RACI is the single person who owns the decision outcome and is answerable if things go wrong — only ONE person can hold A per task. The CIO&#x27;s authority to make the final go/no-go call is the defining characteristic of the Accountable role. The CMIO, CNO, and vendor are Responsible (doing the evaluation work) or Consulted (providing input)."},
{"id":"RW-D4-90","domain":3,"cog":"AP","correct":"B","task":"Task 4.7","stem":"A hospital informatics team has developed a new CDS alert that automatically flags opioid prescriptions above a threshold dose for mandatory pharmacist review. Because the alert affects prescribing autonomy and clinical workflow across multiple departments, it requires formal multi-stakeholder review and approval before deployment. Which governance body is MOST appropriate to route this approval through?","opts":[{"l":"A","c":false,"t":"Change Advisory Board (CAB) — which reviews technical change control requests"},{"l":"B","c":true,"t":"Clinical Informatics Committee — which governs EHR workflow standards and CDS policy"},{"l":"C","c":false,"t":"Data Governance Council — which oversees data standards and data quality policy"},{"l":"D","c":false,"t":"Privacy and Security Committee — which manages privacy policy and breach response"}],"rat":"The Clinical Informatics Committee governs clinical HIT decisions including CDS governance, EHR workflow standards, and clinical policy affecting providers. CAB reviews technical infrastructure changes; Data Governance handles data definitions and quality standards; Privacy/Security handles access and breach management."},
{"id":"RW-D4-91","domain":3,"cog":"AP","correct":"B","task":"Task 4.8","stem":"A hospital establishes three tiers of IT access control documentation: the first document states the organization&#x27;s mandatory requirements and principles for identity and access management. The second describes step-by-step how IT administrators implement those requirements for each system. The third is a quick-reference checklist for provisioning a new user account. These three documents represent, in order:","opts":[{"l":"A","c":false,"t":"Procedure → Policy → Work instruction"},{"l":"B","c":true,"t":"Policy → Procedure → Work instruction"},{"l":"C","c":false,"t":"Standard → Guideline → Policy"},{"l":"D","c":false,"t":"Work instruction → Standard → Policy"}],"rat":"The policy hierarchy flows from most authoritative to most specific: Policy (mandatory organizational rules and principles) → Procedure (step-by-step implementation instructions for a department) → Work instruction (task-specific reference or checklist). Policies govern; procedures implement; work instructions guide specific actions."},
{"id":"RW-D4-92","domain":3,"cog":"AP","correct":"B","task":"Task 4.7","stem":"An IS director overseeing an EHR replacement defines: nursing leadership receives weekly status email updates; the board of directors receives a monthly executive summary dashboard; end users receive monthly training bulletins; the vendor project team meets daily via stand-up. Documenting who receives what message, through which channel, and at what frequency constitutes:","opts":[{"l":"A","c":false,"t":"Stakeholder impact analysis — mapping how much each group&#x27;s workflow will change"},{"l":"B","c":true,"t":"Stakeholder communication plan — defining tailored communication for each audience throughout the project"},{"l":"C","c":false,"t":"Force field analysis — identifying driving and restraining forces for the change"},{"l":"D","c":false,"t":"Change readiness assessment — measuring how prepared stakeholders are for the change"}],"rat":"A stakeholder communication plan defines the who (audience), what (message content), how (channel), and when (frequency) of project communications — ensuring each group receives appropriately tailored, timely information. It is distinct from stakeholder impact analysis (which maps workflow disruption) and change readiness assessment (which measures willingness to change)."},
{"id":"RW-D4-93","domain":3,"cog":"AP","correct":"B","task":"Task 4.7","stem":"A hospital board of directors approves the organization&#x27;s IT risk tolerance thresholds and authorizes a $10M EHR modernization budget. The CIO is responsible for selecting vendors, managing project execution, and delivering the approved milestones. According to IT governance frameworks such as COBIT, these represent which two distinct functions?","opts":[{"l":"A","c":false,"t":"Portfolio management (board) and project management (CIO)"},{"l":"B","c":true,"t":"Governance (board sets direction, approves risk appetite, and authorizes resources) and management (CIO plans, builds, runs, and monitors within that direction)"},{"l":"C","c":false,"t":"Strategic planning (board) and tactical planning (CIO) — equivalent functions at different levels"},{"l":"D","c":false,"t":"ITIL service design (board) and service operation (CIO)"}],"rat":"COBIT distinguishes governance (board and executive responsibility: evaluate, direct, and monitor — set risk tolerance, approve strategy, authorize investment) from management (CIO/IT operations responsibility: plan, build, run, and monitor within the direction set by governance). This separation of roles is a core IT governance principle and prevents operational leaders from self-approving their own risk thresholds."}
];
